// CLX Stripe Provision v1 — Resolve inputs + plan mapping (TASK 3)
// Takes a manual-webhook body and normalises it into the shape the
// downstream Stripe HTTP calls expect. Plan key maps to Stripe Price
// ID — Mary sets these via .env STRIPE_PRICE_<KEY>. Unknown plan
// keys short-circuit with _skip=true and log STRIPE_PROVISION_FAILED.

const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};

const client_id      = body.client_id || null;
const client_email   = body.client_email || null;
const business_name  = body.business_name || null;
const selected_plan  = body.selected_plan || 'founding_1997';

const PLAN_ENV_MAP = {
  founding_1997:     'STRIPE_PRICE_FOUNDING_1997',
  standard_2497:     'STRIPE_PRICE_STANDARD_2497',
  salon_997:         'STRIPE_PRICE_SALON_997',
  intelligence_3997: 'STRIPE_PRICE_INTELLIGENCE_3997',
  construction_1497: 'STRIPE_PRICE_CONSTRUCTION_1497',
  moving_997:        'STRIPE_PRICE_MOVING_997',
  cleaning_997:      'STRIPE_PRICE_CLEANING_997'
};

const envKey = PLAN_ENV_MAP[selected_plan];
const price_id = envKey ? (process.env[envKey] || ('TODO_' + envKey)) : null;

if (!client_email || !price_id) {
  return { json: { _skip: true, skip_reason: !client_email ? 'missing_client_email' : 'unknown_plan_key', selected_plan, client_email, business_name } };
}

return {
  json: {
    client_id,
    client_email,
    business_name,
    selected_plan,
    price_id,
    trial_days: 14
  }
};

// CLX Stripe Provision v1 — Parse Customer create response

const resp = $input.item.json || {};
const inputs = $('Resolve Inputs').first().json;

const ok = !!(resp.id && String(resp.id).startsWith('cus_'));
const stripe_customer_id = ok ? resp.id : null;
const error_message = ok ? null : (resp.error && resp.error.message) || (resp.message) || JSON.stringify(resp).slice(0, 500);

return {
  json: {
    ...inputs,
    stripe_customer_ok: ok,
    stripe_customer_id,
    stripe_customer_error: error_message
  }
};

// CLX Stripe Provision v1 — Parse Subscription response

const resp = $input.item.json || {};
const prev = $('Parse Customer Response').first().json;

const ok = !!(resp.id && String(resp.id).startsWith('sub_'));
const stripe_subscription_id = ok ? resp.id : null;
const subscription_status = resp.status || null;
const trial_end = resp.trial_end ? new Date(resp.trial_end * 1000).toISOString() : null;
const current_period_end = resp.current_period_end ? new Date(resp.current_period_end * 1000).toISOString() : null;
const next_billing_date = current_period_end ? current_period_end.slice(0, 10) : null;
const error_message = ok ? null : (resp.error && resp.error.message) || (resp.message) || JSON.stringify(resp).slice(0, 500);

return {
  json: {
    ...prev,
    stripe_subscription_ok: ok,
    stripe_subscription_id,
    subscription_status,
    trial_end,
    next_billing_date,
    stripe_subscription_error: error_message
  }
};

// CLX Stripe Provision v1 — Build welcome email (TESTING MODE)
// TESTING MODE redirect matches the existing sender-workflow pattern.
// When Mary flips to production, replace the hardcoded to with
// data.client_email.

const data = $input.item.json;
const to = 'adesholaakintunde+clxtest@gmail.com'; // TESTING MODE — remove before production
const subject = 'Welcome to Crystallux — your account is ready';
const fromName = 'Mary Akintunde (Crystallux)';
const fromEmail = 'info@crystallux.org';
const businessName = data.business_name || 'your business';
const plan = data.selected_plan || 'founding_1997';
const trialEnd = data.trial_end ? new Date(data.trial_end).toLocaleDateString('en-CA') : 'the end of your trial';
const portalUrl = 'https://billing.stripe.com/p/login/PLACEHOLDER_PORTAL_URL'; // TODO: replace with real Stripe Customer Portal URL

const htmlBody = [
  '<div style="font-family:system-ui,Segoe UI,Arial,sans-serif;max-width:620px;margin:0 auto;color:#1a202c;line-height:1.5;">',
  '  <p>Welcome to Crystallux, ' + businessName + '.</p>',
  '  <p>Your account is provisioned and your 14-day trial has started. Your billing plan is <strong>' + plan + '</strong> and your first payment will be on ' + trialEnd + ' unless you cancel before then.</p>',
  '  <p>Manage your billing, update your card, or cancel any time from the Stripe customer portal:</p>',
  '  <p style="text-align:center;margin:24px 0;"><a href="' + portalUrl + '" style="display:inline-block;background:#2563eb;color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;">Manage Billing</a></p>',
  '  <p>We\'ll be in touch within 24 hours to kick off your onboarding call.</p>',
  '  <p>Talk soon,<br/>Mary</p>',
  '  <hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0;" />',
  '  <p style="font-size:12px;color:#718096;">Mary Akintunde, Crystallux &mdash; <a href="https://crystallux.org" style="color:#718096;">crystallux.org</a></p>',
  '</div>'
].join('\n');

const encodedSubject = '=?UTF-8?B?' + Buffer.from(subject, 'utf8').toString('base64') + '?=';
const mime = [
  'From: "' + fromName + '" <' + fromEmail + '>',
  'To: ' + to,
  'Subject: ' + encodedSubject,
  'MIME-Version: 1.0',
  'Content-Type: text/html; charset=utf-8',
  'Content-Transfer-Encoding: 7bit',
  '',
  htmlBody
].join('\r\n');

const raw = Buffer.from(mime, 'utf8').toString('base64')
  .replace(/\+/g, '-')
  .replace(/\//g, '_')
  .replace(/=+$/, '');

return { json: { ...data, gmail_raw: raw, to_address: to } };
